@spec tracker_page_spec  src=tests/specs/tracker_page_spec.lua  loc=274  sha=ef4e5a4  cases=9
@exercises configManager (h.cm), commandManager (h.cmgr), midiManager (h.mm), trackerManager (h.tm)
@surface   cm:setContext, cmgr:push, cmgr:invoke, cm:getAt, mm:subscribe, mm:notes, tm:assignEvent, tm:byUuid, tm:flush
@harness   mk, reaper:addItem, reaper:seedMidi

# Intent
  Pin-tests for trackerPage's Page interface (bind / unbind / focusState / bind-from-cursor).
  render / handleInput are stubs wired in step 3 and verified in REAPER, not here.

# Helpers
  @fn resetArrange()  @ 44-65
  @fn newTrackerPage(cm, ds, cmgr, chrome, gui)  @ 77-84

# Cases
  @case 'bind(take) drives cm:setContext via the page's own tm:bindTake'  [harness]  @ 88-96
  @case 'unbind() drives cm:setContext(nil) via the page's own tm:bindTake'  [harness]  @ 99-108
  @case 'focusState before any render returns both bits false'  [harness]  @ 111-118
  @case 'bindFromSelection binds tm to the resolved selection take, drops when the track has no slots'  [harness]  @ 124-137
  @case 'newTakeBelow + duplicateUnpooledBelow mint a parked slot on scratch and select it'  [harness]  @ 141-162
  @case 'prev/next track + take drive the tv selection, not the arrange cursor'  [harness]  @ 166-189
  @case 'empty grid shows the single no-takes message'  [harness]  @ 195-209
  @case 'an owned tm flush resyncs the watcher baseline; only a foreign write trips the reload'  [harness]  @ 216-248
  @case 'bindFromSelection re-keys cm on return from dormancy even when the take is unchanged'  [harness]  @ 252-272

# Uses (outbound edges)
  @use call cm:setContext  @ 99
  @use call cmgr:push  @ 150,179
  @use call cmgr:invoke  @ 152,158,181,183,185,187
  @use call cm:getAt  @ 156,160,182,184,186,188
